  ('dietitian-moex-01933', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '個案以高興的語氣對營養師說：「我現在的身材已經可以穿得下市面上一般尺寸的衣服。」營養師說： 「你一定感覺很輕鬆快樂，不用擔心肥胖買不到喜歡的衣服」。此時營養師的回應，較符合下列何種諮 商技巧？', '["反映", "解釋", "訊息提供", "簡述語意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
