  ('dietitian-moex-01935', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某縣市教育局欲推動「多吃全穀」計畫，經SWOT分析發現：「該縣市未設置跨局處專責單位推動食育 議題、且營養師人數少、宣導成效不佳」。上述的分析是屬於SWOT中的那一項？', '["Strengths", "Weakness", "Opportunities", "Threats"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
